// Normalize RemoteOK jobs into our common lead shape and filter by keyword.
// RemoteOK returns a JSON array; n8n emits one item per element. The very
// first element is API metadata (legal notice) and has no id/position.
const cfg = $('Config').first().json;
const keywords = String(cfg.keyword || '')
  .toLowerCase().split(',').map(s => s.trim()).filter(Boolean);

const out = [];
for (const item of $input.all()) {
  const j = item.json || {};
  if (!j.id || !j.position) continue;            // skip metadata / malformed
  const role = String(j.position || '').trim();
  const tags = Array.isArray(j.tags) ? j.tags : [];
  const haystack = (role + ' ' + tags.join(' ')).toLowerCase();
  if (keywords.length && !keywords.some(k => haystack.includes(k))) continue;

  out.push({ json: {
    company: String(j.company || '').trim(),
    role,
    location: String(j.location || '').replace(/,\s*$/, '').trim() || 'Remote',
    url: String(j.url || j.apply_url || ''),
    tags,
    source: 'RemoteOK',
    email: '',
  }});
}
return out;

// Normalize Arbeitnow jobs into our common lead shape and filter by keyword.
// Arbeitnow returns an object { data: [...] } as a single item.
const cfg = $('Config').first().json;
const keywords = String(cfg.keyword || '')
  .toLowerCase().split(',').map(s => s.trim()).filter(Boolean);

// Collect the job records defensively (handles single object or split items).
const jobs = [];
for (const item of $input.all()) {
  const j = item.json || {};
  if (Array.isArray(j.data)) jobs.push(...j.data);
  else if (j.company_name || j.title) jobs.push(j);
}

const out = [];
for (const j of jobs) {
  const role = String(j.title || '').trim();
  const tags = Array.isArray(j.tags) ? j.tags : [];
  const haystack = (role + ' ' + tags.join(' ')).toLowerCase();
  if (keywords.length && !keywords.some(k => haystack.includes(k))) continue;

  out.push({ json: {
    company: String(j.company_name || '').trim(),
    role,
    location: String(j.location || '').trim() || (j.remote ? 'Remote' : ''),
    url: String(j.url || ''),
    tags,
    source: 'Arbeitnow',
    email: '',
  }});
}
return out;

// Clean + normalise fields, remove duplicates, guess a company domain for
// enrichment, and cap the list so we stay within Hunter's free quota.
const cfg = $('Config').first().json;
const maxLeads = Number(cfg.maxLeads) || 30;

function cleanCompany(name) {
  return String(name || '').replace(/\s+/g, ' ').trim();
}
function normKey(s) {
  return String(s || '')
    .toLowerCase()
    .replace(/\b(inc|llc|ltd|gmbh|corp|co|company|group|the)\b/g, '')
    .replace(/[^a-z0-9]/g, '');
}
function guessDomain(company) {
  const base = normKey(company);
  return base ? base + '.com' : '';
}

const seen = new Set();
const out = [];
for (const item of $input.all()) {
  const j = item.json || {};
  const company = cleanCompany(j.company);
  const role = String(j.role || '').replace(/\s+/g, ' ').trim();
  if (!company || !role) continue;                 // drop records missing core fields

  const key = normKey(company) + '|' + normKey(role);
  if (seen.has(key)) continue;                     // de-duplicate on company+role
  seen.add(key);

  out.push({ json: {
    company,
    role,
    location: String(j.location || '').replace(/\s+/g, ' ').trim() || 'Not specified',
    url: String(j.url || ''),
    tags: Array.isArray(j.tags) ? j.tags : [],
    source: String(j.source || ''),
    domain: guessDomain(company),
    email: 'not found',
  }});

  if (out.length >= maxLeads) break;               // protect Hunter free-tier credits
}
return out;

// Pair each Hunter response back to its source lead (order is preserved) and
// attach the best email found. Gracefully handles no-email / API errors.
const sources = $('Clean & Dedupe').all();
const responses = $input.all();

const out = [];
for (let i = 0; i < responses.length; i++) {
  const lead = { ...(sources[i] ? sources[i].json : responses[i].json) };
  const body = responses[i].json || {};
  const data = body.data || {};

  let email = 'not found';
  let confidence = 0;
  if (Array.isArray(data.emails) && data.emails.length) {
    // Prefer a generic/role email for outreach, else the highest-confidence one.
    const sorted = [...data.emails].sort((a, b) => (b.confidence || 0) - (a.confidence || 0));
    email = sorted[0].value || 'not found';
    confidence = sorted[0].confidence || 0;
  }
  lead.email = email;
  lead.email_confidence = confidence;
  out.push({ json: lead });
}
return out;

// Lead score (0-100). The keyword-relevance component uses Gemini embedding
// similarity when available, and falls back to rule-based keyword matching
// when embeddings are absent (no API key / call failed). Other components
// (seniority, location, email) stay rule-based.
const cfg = $('Config').first().json;
const wantKeywords = String(cfg.keyword || '').toLowerCase().split(',').map(s => s.trim()).filter(Boolean);
const wantLocation = String(cfg.location || '').toLowerCase().trim();
const SENIORITY = ['chief', 'vp', 'vice president', 'head', 'director', 'principal', 'staff', 'lead', 'senior', 'sr.'];

// Keyword embedding vector (null if the Embed Keyword step produced nothing).
let kwVec = null;
try { kwVec = $('Embed Keyword (Gemini)').first().json?.embedding?.values || null; } catch (e) { kwVec = null; }

function cosine(a, b) {
  let dot = 0, na = 0, nb = 0;
  for (let i = 0; i < a.length; i++) { dot += a[i] * b[i]; na += a[i] * a[i]; nb += b[i] * b[i]; }
  return (na && nb) ? dot / (Math.sqrt(na) * Math.sqrt(nb)) : 0;
}

const sources = $('Attach Email').all();   // the leads (all fields), paired by index
const responses = $input.all();            // Embed Role responses, paired by index

const out = [];
for (let i = 0; i < responses.length; i++) {
  const j = { ...(sources[i] ? sources[i].json : responses[i].json) };
  const role = String(j.role || '').toLowerCase();
  const loc = String(j.location || '').toLowerCase();
  const reasons = [];
  let score = 0;

  // 1) Keyword relevance — embedding similarity (0-40) or rule-based fallback (0-35)
  const roleVec = responses[i].json?.embedding?.values || null;
  if (kwVec && roleVec) {
    const sim = cosine(kwVec, roleVec);
    const pts = Math.round(Math.max(0, Math.min(1, (sim - 0.5) / 0.4)) * 40);
    score += pts;
    j.semantic_similarity = Math.round(sim * 1000) / 1000;
    reasons.push(`semantic match ${j.semantic_similarity} (+${pts})`);
  } else {
    const hits = wantKeywords.filter(k => role.includes(k)).length;
    if (hits > 0) { const pts = Math.min(35, 20 + hits * 15); score += pts; reasons.push(`keyword x${hits} (+${pts})`); }
    j.semantic_similarity = '';
  }

  // 2) Seniority signal (20)
  if (SENIORITY.some(s => role.includes(s))) { score += 20; reasons.push('seniority (+20)'); }

  // 3) Location match (15) or remote-friendly (5)
  if (wantLocation && loc.includes(wantLocation)) { score += 15; reasons.push('location match (+15)'); }
  else if (loc.includes('remote')) { score += 5; reasons.push('remote (+5)'); }

  // 4) A verified contact email was found (30)
  if (j.email && j.email !== 'not found') {
    const conf = Number(j.email_confidence) || 0;
    const pts = conf >= 80 ? 30 : conf >= 50 ? 20 : 15;
    score += pts; reasons.push(`email found conf ${conf} (+${pts})`);
  }

  j.score = Math.max(0, Math.min(100, score));
  j.score_reasons = reasons.join('; ');
  delete j.tags;      // internal only — keep the exported CSV clean
  delete j.domain;    // internal (used for Hunter lookup)
  out.push({ json: j });
}

// Rank best leads first.
out.sort((a, b) => b.json.score - a.json.score);
return out;

// AI/ML stretch: build the Google Gemini request body for a one-line,
// personalised outreach hook per lead. The model + key come from env vars
// (GEMINI_MODEL / GEMINI_API_KEY), read by the HTTP node — never hard-coded.
const out = [];
for (const item of $input.all()) {
  const j = { ...item.json };
  const company = String(j.company || 'the company');
  const role = String(j.role || 'the role');
  const location = String(j.location || '').trim();

  const prompt =
    `Company: ${company}\n` +
    `Role they are hiring for: ${role}\n` +
    (location ? `Location: ${location}\n` : '') +
    `\nWrite ONE friendly, specific first-line outreach hook (max 25 words) to send this company ` +
    `about helping them hire for this role. Output only the single sentence — no greeting, no sign-off, ` +
    `no quotes. Do not invent facts about the company.`;

  j.geminiBody = {
    systemInstruction: { parts: [{ text: 'You write concise, specific B2B sales outreach opening lines. Output only the single sentence, nothing else.' }] },
    contents: [{ parts: [{ text: prompt }] }],
    generationConfig: { maxOutputTokens: 120, temperature: 0.8 },
  };
  out.push({ json: j });
}
return out;

// Pair each Gemini response back to its lead (order preserved) and attach the
// outreach hook. Continues gracefully if a single call errored.
const sources = $('Build Gemini Request').all();
const responses = $input.all();

const out = [];
for (let i = 0; i < responses.length; i++) {
  const lead = { ...(sources[i] ? sources[i].json : responses[i].json) };
  delete lead.geminiBody;                          // don't export the request payload

  const body = responses[i].json || {};
  let hook = 'not generated';
  const parts = body?.candidates?.[0]?.content?.parts;
  if (Array.isArray(parts) && parts.length && parts[0].text) {
    hook = String(parts[0].text).replace(/^["'\s]+|["'\s]+$/g, '');
  }
  lead.outreach_hook = hook;
  out.push({ json: lead });
}
return out;
